  function rwphUpdateLogoButtons() {
    const key = rwphGetLogoChoiceKey();
    const asset = rwphGetLogoAsset(key);
    document.querySelectorAll?.("#rw-current-logo-label").forEach((el) => { el.textContent = asset.label; });
    document.querySelectorAll?.("[data-rwph-logo-choice]").forEach((btn) => {
      const active = String(btn.dataset.rwphLogoChoice || "") === key;
      btn.classList.toggle("primary", active);
      btn.classList.toggle("secondary", !active);
      btn.setAttribute("aria-pressed", active ? "true" : "false");
    });
  }

  function rwphApplyLogoChoice() {
    const asset = rwphGetLogoAsset();
    rwphEnsureDynamicLogoCss();
    document.documentElement.style.setProperty("--rwph-logo-icon-url", `url("${asset.icon}")`);
    document.documentElement.style.setProperty("--rwph-logo-banner-url", `url("${asset.banner}")`);
    document.querySelectorAll?.(".rwph-dynamic-logo-icon").forEach((img) => { if (img && img.src !== asset.icon) img.src = asset.icon; });
    document.querySelectorAll?.(".rwph-dynamic-logo-banner").forEach((img) => { if (img && img.src !== asset.banner) img.src = asset.banner; });
    rwphUpdateLogoButtons();
  }

