  function rwphLayoutThemeLabel(key = rwphGetPanelThemeKey()) {
    const labels = {
      bronze: "Default RWPH Bronze",
      aurora: "Aurora Command",
      neonforge: "Neon Forge Grid",
      crimsonledger: "Crimson Ledger Cards",
      frostline: "Frostline Minimal"
    };
    return labels[String(key || "bronze").toLowerCase()] || labels.bronze;
  }

