  function rwphApplyPanelThemeChoice() {
    const themeKey = rwphGetPanelThemeKey();
    const theme = rwphGetPanelThemePreset(themeKey);
    let style = document.getElementById("rwph-panel-theme-choice-v1379");
    if (!style) {
      style = document.createElement("style");
      style.id = "rwph-panel-theme-choice-v1379";
      (document.head || document.documentElement).appendChild(style);
    }
    style.textContent = rwphPanelThemeCss(theme) + "\n" + rwphAdvancedLayoutThemeCss(themeKey);
    document.documentElement.setAttribute("data-rwph-panel-theme", themeKey);
    rwphUpdateLayoutThemeButtons();
  }

  function rwphClosePanelThemePicker() {
    const panel = document.getElementById("rwph-layout-theme-panel") || document.getElementById("rwph-panel-theme-picker");
    if (panel) panel.remove();
  }

  function rwphSetLayoutThemeChoice(themeKey) {
    const requested = String(themeKey || "bronze").toLowerCase();
    const allowed = new Set(["bronze", "aurora", "neonforge", "crimsonledger", "frostline"]);
    const nextKey = allowed.has(requested) ? requested : "bronze";
    GM_setValue(PANEL_THEME_STORAGE_KEY, nextKey);
    rwphApplyPanelThemeChoice();
  rwphApplyLogoChoice();
    rwphUpdateLayoutThemeButtons();
    rwphShowToast(`RWPH layout changed to ${rwphLayoutThemeLabel(nextKey)}.`, "info", 7000, "RWPH Layout / Theme");
  }

  function rwphUpdateLayoutThemeButtons() {
    const key = rwphGetPanelThemeKey();
    document.querySelectorAll?.("#rw-current-layout-label").forEach((el) => { el.textContent = rwphLayoutThemeLabel(key); });
    document.querySelectorAll?.("[data-rwph-layout-theme-choice]").forEach((btn) => {
      const active = String(btn.dataset.rwphLayoutThemeChoice || "bronze") === key;
      btn.classList.toggle("primary", active);
      btn.classList.toggle("secondary", !active);
      btn.setAttribute("aria-pressed", active ? "true" : "false");
    });
  }

  function rwphOpenPanelThemePicker() {
    rwphClosePanelThemePicker();
    rwphApplyPanelThemeChoice();
    rwphEnsureFloatingPanelCss();
    const key = rwphGetPanelThemeKey();
    const panel = document.createElement("div");
    panel.id = "rwph-layout-theme-panel";
    panel.className = "rwph-floating-panel rwph-layout-theme-panel rwph-layout-theme-panel-controls";
    panel.dataset.layoutKey = "rwph_layout_theme_panel_layout";
    panel.setAttribute("role", "dialog");
    panel.setAttribute("aria-label", "RWPH Layout / Theme");
    panel.style.cssText = `
      position: fixed;
      z-index: 1000004;
      right: 18px;
      top: 120px;
      width: min(540px, calc(100vw - 18px));
      height: min(660px, calc(100vh - 18px));
      max-width: calc(100vw - 16px);
      max-height: calc(100vh - 16px);
      min-width: min(300px, calc(100vw - 18px));
      min-height: 260px;
      overflow: hidden;
      display: flex;
      flex-direction: column;
      color: #fff7ed;
      font-family: Inter, Segoe UI, Arial, sans-serif;
    `;
    panel.innerHTML = `
      <div class="rwph-panel-head rwph-layout-theme-head" style="display:flex;align-items:center;justify-content:space-between;gap:10px;padding:12px 14px;border-bottom:1px solid rgba(255,255,255,.10);cursor:move;touch-action:none;-webkit-user-select:none;user-select:none;flex:0 0 auto;">
        <div style="display:flex;align-items:center;gap:10px;font-weight:950;min-width:0;"><img class="rwph-dynamic-logo-icon" src="${rwphCurrentLogoIconUri()}" alt="RWPH" style="width:42px;height:42px;object-fit:contain;pointer-events:none;flex:0 0 auto;"><span style="min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">Layout / Theme</span></div>
        <button id="rwph-layout-theme-close" class="danger" type="button" title="Close" aria-label="Close" style="margin:0;">×</button>
      </div>
      <div class="rwph-floating-panel-body rwph-layout-theme-body" style="padding:14px;overflow-y:auto;overflow-x:hidden;flex:1 1 auto;min-height:0;">
        <div class="rw-layout-theme-current rw-card" style="padding:12px;border:1px solid rgba(255,255,255,.12);border-radius:14px;margin-bottom:12px;">
          <b>Current layout:</b> <span id="rw-current-layout-label">${esc(rwphLayoutThemeLabel(key))}</span><br>
          <span class="rw-muted">This switch changes panel layout, button positioning, tabs, calculation controls, sections, cards, inputs, checkboxes/dropdowns, payment/member panels, and popup notification styling.</span>
        </div>
        <div class="rwph-layout-theme-options">
          <button type="button" class="rwph-layout-theme-option ${key === "bronze" ? "primary" : "secondary"}" data-rwph-layout-theme-choice="bronze" aria-pressed="${key === "bronze" ? "true" : "false"}">
            <span style="display:block;font-weight:950;">Default RWPH Bronze</span>
            <small style="display:block;margin-top:5px;font-weight:700;line-height:1.35;">Original safe compact layout from v1.1.428.</small>
          </button>
          <button type="button" class="rwph-layout-theme-option ${key === "aurora" ? "primary" : "secondary"}" data-rwph-layout-theme-choice="aurora" aria-pressed="${key === "aurora" ? "true" : "false"}">
            <span style="display:block;font-weight:950;">Advanced Aurora Command</span>
            <small style="display:block;margin-top:5px;font-weight:700;line-height:1.35;">Full rebuilt clean layout with new colours, round command buttons, grid controls, card sections, payment/member reflow, and themed popups.</small>
          </button>
          <button type="button" class="rwph-layout-theme-option ${key === "neonforge" ? "primary" : "secondary"}" data-rwph-layout-theme-choice="neonforge" aria-pressed="${key === "neonforge" ? "true" : "false"}">
            <span style="display:block;font-weight:950;">Neon Forge Grid</span>
            <small style="display:block;margin-top:5px;font-weight:700;line-height:1.35;">Wide cyber grid layout with hard-edge cards, neon buttons, grid controls, compact payments, member cards, and sharp popups.</small>
          </button>
          <button type="button" class="rwph-layout-theme-option ${key === "crimsonledger" ? "primary" : "secondary"}" data-rwph-layout-theme-choice="crimsonledger" aria-pressed="${key === "crimsonledger" ? "true" : "false"}">
            <span style="display:block;font-weight:950;">Crimson Ledger Cards</span>
            <small style="display:block;margin-top:5px;font-weight:700;line-height:1.35;">Stacked ledger layout with vertical tabs, sharp action blocks, red/gold cards, list payments, and tactical popups.</small>
          </button>
          <button type="button" class="rwph-layout-theme-option ${key === "frostline" ? "primary" : "secondary"}" data-rwph-layout-theme-choice="frostline" aria-pressed="${key === "frostline" ? "true" : "false"}">
            <span style="display:block;font-weight:950;">Frostline Minimal</span>
            <small style="display:block;margin-top:5px;font-weight:700;line-height:1.35;">Clean frosted layout with soft split cards, roomy fitted controls, rounded buttons, clean inputs, and smooth notification panels.</small>
          </button>
        </div>
      </div>
    `;
    document.body.appendChild(panel);
    panel.querySelector("#rwph-layout-theme-close")?.addEventListener("click", rwphClosePanelThemePicker);
    panel.addEventListener("click", (event) => {
      const btn = event.target?.closest?.("[data-rwph-layout-theme-choice]");
      if (!btn || !panel.contains(btn)) return;
      event.preventDefault();
      rwphSetLayoutThemeChoice(btn.dataset.rwphLayoutThemeChoice || "bronze");
    });
    rwphEnablePanelMoveResize(panel, ".rwph-panel-head");
    rwphUpdateLayoutThemeButtons();
  }

  function attachPanelThemeButton() {
    const btn = document.getElementById("rw-open-theme-picker");
    if (!btn || btn.dataset.rwphThemeReady === "1") return;
    btn.dataset.rwphThemeReady = "1";
    btn.addEventListener("click", (event) => {
      event.preventDefault();
      rwphOpenPanelThemePicker();
    });
    rwphUpdateLayoutThemeButtons();
  }


  function rwphCloseLogoPicker() {
    document.getElementById("rwph-logo-picker-panel")?.remove();
  }

  function rwphOpenLogoPicker() {
    rwphCloseLogoPicker();
    rwphApplyPanelThemeChoice();
    rwphApplyLogoChoice();
    rwphEnsureFloatingPanelCss();
    const key = rwphGetLogoChoiceKey();
    const current = rwphGetLogoAsset(key);
    const panel = document.createElement("div");
    panel.id = "rwph-logo-picker-panel";
    panel.className = "rwph-floating-panel rwph-layout-theme-panel rwph-layout-theme-panel-controls rwph-logo-picker-panel";
    panel.dataset.layoutKey = "rwph_logo_picker_panel_layout";
    panel.setAttribute("role", "dialog");
    panel.setAttribute("aria-label", "RWPH Logo Selector");
    panel.style.cssText = `
      position: fixed;
      z-index: 1000005;
      right: 18px;
      top: 136px;
      width: min(720px, calc(100vw - 18px));
      height: min(700px, calc(100vh - 18px));
      max-width: calc(100vw - 16px);
      max-height: calc(100vh - 16px);
      min-width: min(320px, calc(100vw - 18px));
      min-height: 280px;
      overflow: hidden;
      display: flex;
      flex-direction: column;
      color: #fff7ed;
      font-family: Inter, Segoe UI, Arial, sans-serif;
    `;
    const optionsHtml = Object.entries(RWPH_LOGO_PRESETS).map(([logoKey, asset]) => `
      <button type="button" class="rwph-layout-theme-option rwph-logo-picker-option ${logoKey === key ? "primary" : "secondary"}" data-rwph-logo-choice="${logoKey}" aria-pressed="${logoKey === key ? "true" : "false"}">
        <img src="${asset.banner}" alt="${esc(asset.label)} preview" loading="lazy">
        <span class="rwph-logo-picker-name">${esc(asset.label)}</span>
        <span class="rwph-logo-picker-note">${esc(asset.description)}</span>
      </button>
    `).join("");
    panel.innerHTML = `
      <div class="rwph-panel-head rwph-layout-theme-head" style="display:flex;align-items:center;justify-content:space-between;gap:10px;padding:12px 14px;border-bottom:1px solid rgba(255,255,255,.10);cursor:move;touch-action:none;-webkit-user-select:none;user-select:none;flex:0 0 auto;">
        <div style="display:flex;align-items:center;gap:10px;font-weight:950;min-width:0;"><img class="rwph-dynamic-logo-icon" src="${rwphCurrentLogoIconUri()}" alt="RWPH" style="width:42px;height:42px;object-fit:contain;pointer-events:none;flex:0 0 auto;"><span style="min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">Logo Selector</span></div>
        <button id="rwph-logo-picker-close" class="danger" type="button" title="Close" aria-label="Close" style="margin:0;">×</button>
      </div>
      <div class="rwph-floating-panel-body rwph-layout-theme-body" style="padding:14px;overflow-y:auto;overflow-x:hidden;flex:1 1 auto;min-height:0;">
        <div class="rwph-logo-current-preview rw-card">
          <b>Current logo:</b> <span id="rw-current-logo-label">${esc(current.label)}</span><br>
          <span class="rw-muted">This switch updates the launcher logo and the RWPH logos shown through the main panels and floating panels. Launcher buttons use a fitted icon crop from the selected logo set.</span>
          <img class="rwph-dynamic-logo-banner" src="${rwphCurrentLogoBannerUri()}" alt="Current RWPH logo preview">
        </div>
        <div class="rwph-logo-picker-options">${optionsHtml}</div>
      </div>
    `;
    document.body.appendChild(panel);
    panel.querySelector("#rwph-logo-picker-close")?.addEventListener("click", rwphCloseLogoPicker);
    panel.addEventListener("click", (event) => {
      const btn = event.target?.closest?.("[data-rwph-logo-choice]");
      if (!btn || !panel.contains(btn)) return;
      event.preventDefault();
      rwphSetLogoChoice(btn.dataset.rwphLogoChoice || "royalcrest");
    });
    rwphEnablePanelMoveResize(panel, ".rwph-panel-head");
    rwphApplyLogoChoice();
  }

  function attachLogoPickerButton() {
    const btn = document.getElementById("rw-open-logo-picker");
    if (!btn || btn.dataset.rwphLogoReady === "1") return;
    btn.dataset.rwphLogoReady = "1";
    btn.addEventListener("click", (event) => {
      event.preventDefault();
      rwphOpenLogoPicker();
    });
    rwphApplyLogoChoice();
  }


  function attachMoveLauncherButton() {
    ["rw-move-launcher", "rw-move-launcher-admin"].forEach((id) => {
      const btn = document.getElementById(id);
      if (!btn || btn.dataset.rwphCornerReady === "1") return;
      btn.dataset.rwphCornerReady = "1";
      btn.addEventListener("click", cycleLauncherCorner);
    });
    updateLauncherCornerButtonLabels();
  }

  function closePanel() {
    const panel = document.getElementById("rw-payout-helper");
    if (panel) {
      rwphSavePanelLayout(panel);
      panel.remove();
    }
    rwphSetPanelOpenState(false);
    setLauncherOpenState(false);
  }

  function togglePanel() {
    const panel = document.getElementById("rw-payout-helper");

    if (panel) {
      closePanel();
      return;
    }

    createPanel();
  }

  function apiPost(path, body) {
    return new Promise((resolve, reject) => {
      const safePath = String(path || "");
      const requestTimeout = safePath.includes("/api/calc/") ? 300000 : 120000;
      GM_xmlhttpRequest({
        method: "POST",
        url: `${PAYWALL_API_BASE}${path}`,
        headers: { "Content-Type": "application/json" },
        data: JSON.stringify(body || {}),
        timeout: requestTimeout,
        onload: (res) => {
          try {
            const json = JSON.parse(res.responseText || "{}");
            if (!json.ok) {
              const err = new Error(json.error || `Server error ${res.status}`);
              err.retryAfterSeconds = Number(json.retryAfterSeconds || 0);
              err.cooldownEndsAtMs = Number(json.cooldownEndsAtMs || 0);
              err.status = Number(res.status || 0);
              reject(err);
            } else {
              resolve(json);
            }
          } catch (e) {
            reject(new Error(`Could not parse server response. Status ${res.status}.`));
          }
        },
        onerror: () => reject(new Error("Failed to reach paywall server.")),
        ontimeout: () => reject(new Error("Paywall server request timed out. On phone/Torn PDA, large wars or Torn API delays can take longer; try again or use a cached report if available.")),
      });
    });
  }


  function apiPostCancelable(path, body, options = {}) {
    let request = null;
    let settled = false;
    const promise = new Promise((resolve, reject) => {
      const safePath = String(path || "");
      const requestTimeout = Number(options.timeout || 0) > 0 ? Number(options.timeout) : (safePath.includes("/api/calc/") ? 600000 : 120000);
      request = GM_xmlhttpRequest({
        method: "POST",
        url: `${PAYWALL_API_BASE}${path}`,
        headers: { "Content-Type": "application/json" },
        data: JSON.stringify(body || {}),
        timeout: requestTimeout,
        onload: (res) => {
          settled = true;
          try {
            const json = JSON.parse(res.responseText || "{}");
            if (!json.ok) {
              const err = new Error(json.error || `Server error ${res.status}`);
              err.retryAfterSeconds = Number(json.retryAfterSeconds || 0);
              err.cooldownEndsAtMs = Number(json.cooldownEndsAtMs || 0);
              err.status = Number(res.status || 0);
              err.cancelled = !!json.cancelled;
              reject(err);
            } else {
              resolve(json);
            }
          } catch (e) {
            reject(new Error(`Could not parse server response. Status ${res.status}.`));
          }
        },
        onerror: () => { settled = true; reject(new Error("Failed to reach paywall server.")); },
        ontimeout: () => { settled = true; reject(new Error("Paywall server request timed out. On phone/Torn PDA, large wars or Torn API delays can take longer; try again or use a cached report if available.")); },
        onabort: () => { settled = true; const err = new Error("Calculation cancelled because the results loading tab was closed."); err.cancelled = true; reject(err); },
      });
    });
    return {
      promise,
      abort: () => {
        if (settled) return;
        try { if (request && typeof request.abort === "function") request.abort(); } catch (_) {}
      },
    };
  }

  function rwphSendCalcCancel(progressId, reason = "Results loading tab closed before calculation finished.") {
    const id = String(progressId || "").trim();
    if (!id) return;
    try {
      GM_xmlhttpRequest({
        method: "POST",
        url: `${PAYWALL_API_BASE}/api/calc/cancel`,
        headers: { "Content-Type": "application/json" },
        data: JSON.stringify({ progressId: id, reason }),
        timeout: 10000,
        onload: () => {},
        onerror: () => {},
        ontimeout: () => {},
      });
    } catch (_) {}
  }

  function rwphCleanResponsePreview(text, maxLen = 260) {
    return String(text || "")
      .replace(/<script[\s\S]*?<\/script>/gi, "")
      .replace(/<style[\s\S]*?<\/style>/gi, "")
      .replace(/<[^>]+>/g, " ")
      .replace(/\s+/g, " ")
      .trim()
      .slice(0, maxLen);
  }

  function rwphParseAdminJsonResponse(res) {
    const raw = String(res?.responseText ?? res?.response ?? "");
    const trimmed = raw.trim();

    if (!trimmed) {
      throw new Error(`Admin server returned an empty response. Status ${res?.status || 0}. Make sure the backend/admin route is running.`);
    }

    try {
      return JSON.parse(trimmed);
    } catch (_) {}

    // Some mobile/PDA/tunnel wrappers can return text around the JSON. Try to salvage the JSON object before failing.
    const firstBrace = trimmed.indexOf("{");
    const lastBrace = trimmed.lastIndexOf("}");
    if (firstBrace >= 0 && lastBrace > firstBrace) {
      const possibleJson = trimmed.slice(firstBrace, lastBrace + 1);
      try {
        return JSON.parse(possibleJson);
      } catch (_) {}
    }

    const preview = rwphCleanResponsePreview(trimmed);
    const looksHtml = /<\s*!doctype|<\s*html|ngrok|browser warning|tunnel/i.test(trimmed);
    if (looksHtml) {
      throw new Error(`Admin server returned HTML instead of JSON. Status ${res?.status || 0}. Check the backend URL/tunnel is pointing to the RWPH server and restart the server if needed. Response: ${preview || "HTML page"}`);
    }

    throw new Error(`Could not parse admin server response. Status ${res?.status || 0}. Response: ${preview || "No readable response text"}`);
  }

  function adminRequest(method, path, adminKey, body = {}) {
    return new Promise((resolve, reject) => {
      const isGet = String(method).toUpperCase() === "GET";
      const sep = path.includes("?") ? "&" : "?";
      const url = isGet
        ? `${PAYWALL_API_BASE}${path}${sep}adminKey=${encodeURIComponent(adminKey)}&_rwph=${Date.now()}`
        : `${PAYWALL_API_BASE}${path}`;

      GM_xmlhttpRequest({
        method,
        url,
        responseType: "text",
        headers: {
          "Accept": "application/json, text/plain, */*",
          "Content-Type": "application/json",
          "x-admin-key": adminKey,
          "ngrok-skip-browser-warning": "true",
          "Cache-Control": "no-cache",
        },
        data: isGet ? undefined : JSON.stringify({ ...(body || {}), adminKey, _rwph: Date.now() }),
        timeout: 120000,
        onload: (res) => {
          try {
            const json = rwphParseAdminJsonResponse(res);
            if (!json.ok) {
              const err = new Error(json.error || `Admin server error ${res.status}`);
              err.status = Number(res.status || 0);
              reject(err);
            } else {
              resolve(json);
            }
          } catch (e) {
            reject(e);
          }
        },
        onerror: () => reject(new Error("Failed to reach admin server. Check the backend/tunnel URL and @connect domain.")),
        ontimeout: () => reject(new Error("Admin server request timed out.")),
      });
    });
  }

  function formatUnixDate(unixSeconds) {
    if (!unixSeconds) return "Unknown";
    return new Date(Number(unixSeconds) * 1000).toLocaleString();
  }

  async function grantOwnerLicenseFromAdminKey(adminKey, statusEl) {
    if (!adminKey) throw new Error("Enter your admin key first.");

    const result = await adminRequest("POST", "/api/admin/grant-owner", adminKey, { days: 10000 });

    if (statusEl) {
      rwphToastPanelInfo(
        statusEl,
        `Admin key saved. Owner license granted to ${result.name || "Owner"} (${result.tornId}) until ${formatUnixDate(result.expiresAt)}.`,
        "info",
        "RWPH Admin"
      );
    }

    return result;
  }

  async function extendAdminLicenseFromCurrentForm(statusEl, skipConfirm = false) {
    const adminKey = document.getElementById("rw-admin-key")?.value.trim();
    const tornId = document.getElementById("rw-admin-torn-id")?.value.trim();
    const name = document.getElementById("rw-admin-name")?.value.trim() || `User ${tornId}`;
    const days = Number(document.getElementById("rw-admin-days")?.value || 30);

    if (!adminKey) throw new Error("Enter your admin key first.");
    if (!tornId) throw new Error("Enter a Torn ID first.");
    if (!days || days <= 0) throw new Error("Enter valid extension days.");

    if (!skipConfirm && !confirm(`Extend license for ${name} (${tornId}) by ${days} day(s)?`)) return null;

    GM_setValue(ADMIN_KEY_STORAGE_KEY, adminKey);
    if (statusEl) statusEl.textContent = `Extending ${name} (${tornId}) by ${days} day(s)...`;

    const result = await adminRequest("POST", "/api/admin/extend", adminKey, { tornId, name, days });

    if (statusEl) {
      const previousText = result.previousExpiresAt ? ` Previous expiry: ${formatUnixDate(result.previousExpiresAt)}.` : "";
      rwphToastPanelInfo(
        statusEl,
        `Extended license for ${result.name || name} (${result.tornId || tornId}) by ${result.days || days} day(s).${previousText} New expiry: ${formatUnixDate(result.expiresAt)}.`,
        "info",
        "RWPH Admin"
      );
    }

    return result;
  }

  async function removeAdminLicenseDaysFromCurrentForm(statusEl, skipConfirm = false) {
    const adminKey = document.getElementById("rw-admin-key")?.value.trim();
    const tornId = document.getElementById("rw-admin-torn-id")?.value.trim();
    const name = document.getElementById("rw-admin-name")?.value.trim() || `User ${tornId}`;
    const days = Number(document.getElementById("rw-admin-days")?.value || 30);

    if (!adminKey) throw new Error("Enter your admin key first.");
    if (!tornId) throw new Error("Enter a Torn ID first.");
    if (!days || days <= 0) throw new Error("Enter valid days to remove.");

    if (!skipConfirm && !confirm(`Remove ${days} licence day(s) from ${name} (${tornId})?`)) return null;

    GM_setValue(ADMIN_KEY_STORAGE_KEY, adminKey);
    if (statusEl) statusEl.textContent = `Removing ${days} licence day(s) from ${name} (${tornId})...`;

    const result = await adminRequest("POST", "/api/admin/remove", adminKey, { tornId, name, days });

    if (statusEl) {
      const previousText = result.previousExpiresAt ? ` Previous expiry: ${formatUnixDate(result.previousExpiresAt)}.` : "";
      const endedText = result.expiredNow ? " Licence is now expired." : "";
      rwphToastPanelInfo(
        statusEl,
        `Removed ${result.days || days} licence day(s) from ${result.name || name} (${result.tornId || tornId}).${previousText} New expiry: ${formatUnixDate(result.expiresAt)}.${endedText}`,
        result.expiredNow ? "warn" : "info",
        "RWPH Admin"
      );
    }

    return result;
  }

